import { Anthropic } from '@anthropic-ai/sdk';
import { Vex } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: 'your-key' });
const vex = new Vex({ apiKey: 'your-vex-key' });

const message = await anthropic.messages.create({
  model: 'claude-3-5-sonnet-20240620',
  max_tokens: 1024,
  tools: [{ name: 'ediscovery_scan', inputSchema: {} }, { name: 'privilege_check', inputSchema: {} }],
  messages: [{ role: 'user', content: 'Scan docs for privilege' }],
  tool_choice: 'auto'
});

const verified = await vex.verify({
  agentRun: message,
  policy: 'legal-ediscovery',
  checks: ['conflict_resolution', 'chain_of_custody']
});
if (verified.passed) {
  console.log(message.content[0].text);
} else {
  throw new Error('eDiscovery protocol violation');
}
